/* ──────────────────────────────────────────────────────────────
   ServiceNode.tsx
   Custom ReactFlow node for cloud services.
   - Full-surface connection zone (handles span entire node)
   - Shows provider badge, icon, label, instance type, stats
   - Draggable on canvas by default via React Flow
   ────────────────────────────────────────────────────────────── */
import React, { memo } from 'react';
import { Handle, Position, NodeProps } from 'react-flow-renderer';
import {
  PROVIDER_COLORS,
  CATEGORY_COLORS,
  CloudProvider,
  ServiceCategory,
} from './serviceCatalog';

export interface ServiceNodeData {
  serviceId: string;
  label: string;
  icon: string;
  provider: CloudProvider;
  category: ServiceCategory;
  throughput: number;
  latency: number;
  instanceTypeId?: string;
  instanceLabel?: string;
  vcpus?: number;
  memoryGb?: number;
  replicas?: number;
}

function ServiceNode({ data, selected }: NodeProps<ServiceNodeData>) {
  const providerColor = PROVIDER_COLORS[data.provider] || '#888';
  const categoryColor = CATEGORY_COLORS[data.category] || '#888';

  return (
    <div
      className={`service-node ${selected ? 'selected' : ''}`}
      style={{ borderColor: categoryColor }}
    >
      {/* Full-surface handles — these are invisible overlays that let
          users start / end connections from anywhere on the node */}
      <Handle
        type="target"
        position={Position.Top}
        id="top"
        className="handle-zone handle-zone-top"
      />
      <Handle
        type="target"
        position={Position.Left}
        id="left"
        className="handle-zone handle-zone-left"
      />
      <Handle
        type="source"
        position={Position.Bottom}
        id="bottom"
        className="handle-zone handle-zone-bottom"
      />
      <Handle
        type="source"
        position={Position.Right}
        id="right"
        className="handle-zone handle-zone-right"
      />

      {/* provider strip */}
      <div className="provider-strip" style={{ backgroundColor: providerColor }}>
        {data.provider.toUpperCase()}
      </div>

      {/* body */}
      <div className="node-body">
        <span className="node-icon">{data.icon}</span>
        <div className="node-info">
          <span className="node-label">{data.label}</span>
          {data.instanceLabel && (
            <span className="node-instance">{data.instanceLabel}</span>
          )}
        </div>
      </div>

      {/* specs row (if instance selected) */}
      {data.vcpus != null && (
        <div className="node-specs">
          {data.vcpus > 0 && <span>{data.vcpus} vCPU</span>}
          {data.memoryGb != null && data.memoryGb > 0 && <span>{data.memoryGb} GB</span>}
        </div>
      )}

      {/* stats footer */}
      <div className="node-stats">
        <span title="Throughput (req/s)">⚡ {data.throughput.toLocaleString()}</span>
        <span title="Latency (ms)">⏱ {data.latency}ms</span>
        {data.replicas && data.replicas > 1 && (
          <span title="Replicas">x{data.replicas}</span>
        )}
      </div>
    </div>
  );
}

export default memo(ServiceNode);
